--liquibase formatted sql
--changeset cmpich:0020-grcz11-to-grcz12tu-liftover-welltested.sql splitStatements:false

-- Insert GRCz12tu feature locations produced by UCSC liftOver of GRCz11
-- coordinates (chain danRer11ToGCF_049306965.1.over.chain.gz), restricted to
-- the WELL-TESTED set: net-new placements (feature had a GRCz11 location but no
-- GRCz12tu row) whose lifted position was independently confirmed against ZFIN's
-- directly-sequenced flanking sequence (5' and 3' anchors within <=2 mismatches).
-- Lifted features with no stored flank to test, and those that failed the flank
-- check, are deliberately excluded.
--
-- sa (Sanger) alleles are EXCLUDED from this migration: they are handled
-- separately by the lab of origin.
--
-- 5301 distinct lifted locations covering 5301 non-sa features
-- (duplicate GRCz11 placements that lift to the same GRCz12tu coordinate are
-- collapsed, matching the sfcl alternate key feature+start+end+chromosome+assembly).
-- Each new sfcl row:
--   - sfcl_zdb_id          minted with get_id('SFCL')
--   - registered in zdb_active_data BEFORE the sfcl insert (FK sfcl_zdb_id_fk_odc)
--   - sfcl_evidence_code   inherited from the feature's GRCz11 row (verified: every
--                          feature has exactly one, non-null, distinct value)
--   - accession            the GRCz12tu RefSeq accession liftOver emitted (NC_1331xx.1)
-- The NOT EXISTS guard keeps this idempotent / safe to re-run: features that already
-- have a GRCz12tu row are skipped.

create temp table lifted_wt (feature text, chromosome text, accession text, start1 int, end1 int) on commit drop;


create temp table to_insert_wt on commit drop as
select get_id('SFCL') as sfcl_zdb_id,
       l.feature, l.chromosome, l.accession, l.start1, l.end1,
       (select max(g.sfcl_evidence_code)
          from sequence_feature_chromosome_location g
         where g.sfcl_feature_zdb_id = l.feature
           and g.sfcl_assembly = 'GRCz11') as evidence
  from lifted_wt l
 where not exists (select 1 from sequence_feature_chromosome_location s
                    where s.sfcl_feature_zdb_id = l.feature
                      and s.sfcl_assembly = 'GRCz12tu');

select sfcl_zdb_id from to_insert_wt;

   sfcl_assembly, sfcl_chromosome, sfcl_evidence_code, sfcl_chromosome_reference_accession_number)
select sfcl_zdb_id, feature, start1, end1, 'GRCz12tu', chromosome, evidence, accession
  from to_insert_wt;
